18	/**
19	 * Escape a cell value for markdown tables. Characters like `|` or newlines
20	 * break GFM table rendering, and upstream property data (addresses, labels)
21	 * can legitimately contain both.
22	 */
23	function escapeMarkdownCell(value: unknown): string {
24	  if (value == null) {
25	    return "?";
26	  }
27	  return String(value).replaceAll("|", "\\|").replaceAll(/\r?\n/g, " ").trim();
28	}
